    ($name: ty) => {
        impl<'a> ToTyped for $name {
            fn to_typed(&self) -> Option<TypedValue> {
                // XXX Should return TypedValue::Numeric with unit "number"
                // once that variant is available. Tracked in bug 1990419.
                None
            }
        }
    };
}

