   630→/// A numeric value used by the Typed OM.
   631→///
   632→/// This corresponds to `CSSNumericValue` and its subclasses in the Typed OM
   633→/// specification. It represents numbers that can appear in CSS values,
   634→/// including both simple unit quantities and composite expressions..
   635→///
   636→/// Unlike the parser-level representation, `NumericValue` is property-agnostic
   637→/// and suitable for conversion to or from the `CSSNumericValue` family of DOM
   638→/// objects.
   639→#[derive(Clone, Debug)]
   640→#[repr(C)]
   641→pub enum NumericValue {
   642→    /// A single numeric value with a concrete unit.
